class Solution {
public:
    int leastOpsExpressTarget(int x, int target) {
        if (x == target) return 0;
        if (target == 1) return 1;
        long long t = target;
        int cost = 0;
        vector<int> pos, neg;
        while (t > 0) {
            int d = t % x;
            t /= x;
            pos.push_back(d);
            neg.push_back(d ? x - d : 0);
        }
        int n = pos.size();
        vector<vector<int>> dp(n, vector<int>(2, INT_MAX));
        dp[0][0] = pos[0] * 2;
        dp[0][1] = neg[0] * 2;
        for (int i = 1; i < n; ++i) {
            dp[i][0] = min(dp[i - 1][0] + pos[i], dp[i - 1][1] + pos[i] + 1) + i;
            dp[i][1] = min(dp[i - 1][0] + neg[i], dp[i - 1][1] + neg[i] + 1) + i;
        }
        return min(dp[n - 1][0], dp[n - 1][1]) - 1;
    }
};
